const items = $input.all();
const results = [];

for (const item of items) {
const html = item.json.body?.html || '';
const channel = item.json.body?.channel || '';
const sourceUrl = item.json.body?.source_url || '';

  // Извлекаем текст - убираем все HTML теги
  let text = html;

  // Убираем теги br и p с заменой на пробел
  text = text.replace(/<br\s*\/?>/gi, ' ');
  text = text.replace(/<\/p>|<p[^>]*>/gi, ' ');
  // Убираем ссылки - оставляем текст
  text = text.replace(/<a[^>]*>([^<]*)<\/a>/gi, '$1');
  // Убираем все остальные теги
  text = text.replace(/<[^>]+>/g, '');
  // Декодируем HTML entities
  text = text.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>');
  text = text.replace(/&quot;/g,'"').replace(/&#39;/g,"'").replace(/&nbsp;/g,' ');
  // Убираем лишние пробелы
  text = text.replace(/\s+/g,' ').trim();

  // Извлекаем дату публикации
  const timeMatch = html.match(/datetime="([^"]+)"/);
  const pubTime = timeMatch ? timeMatch[1] : new Date().toISOString();

  console.log('Channel: ' + channel + ' | Text length: ' + text.length);
  console.log('Text preview: ' + text.substring(0, 100));

  if (text && text.length >= 20) {
    results.push({
      json: {
        text: text,
        title: text.substring(0, 100),
        channel: channel,
        source_url: sourceUrl,
        pub_time: pubTime
      }
    });
  }
}

if (results.length === 0) {
  console.log('WARNING: no text extracted from HTML');
}

return results;

const item = $input.item.json;
const title = (item.title || item.text || '').trim().toLowerCase().substring(0, 80);

const now = new Date();
const moscowOffset = 3 * 60 * 60 * 1000;
const moscowNow = new Date(now.getTime() + moscowOffset);
const todayMsk = moscowNow.toISOString().substring(0, 10);

const staticData = $getWorkflowStaticData('global');

// Сброс списка при смене даты МСК
if (staticData.publishedDate !== todayMsk) {
  staticData.published = [];
  staticData.publishedDate = todayMsk;
}
if (!staticData.published) staticData.published = [];

// Если такой заголовок уже публиковался сегодня — блокируем дальше
if (title && staticData.published.includes(title)) {
  return [];
}

return [$input.item];

const content = $input.first().json.choices?.[0]?.message?.content || '';
let score = 0;
let reason = '';
try {
  let cleaned = content.trim().replace(/```(?:json)?\s*/gi,'').replace(/```/g,'').trim();
  if (cleaned.startsWith('{')) {
    const parsed = JSON.parse(cleaned);
    score = parseInt(parsed.score) || 0;
    reason = parsed.reason || '';
  } else {
    const m = content.match(/\b([1-9]|10)\b/);
    score = m ? parseInt(m[1]) : 0;
  }
} catch(e) { score = 0; }
console.log('Score:', score, '| Reason:', reason);
if (score >= 5) {
  const src = $('2. Дедупликация входящих').first().json;
  return [{ json: { ...src, score, score_reason: reason } }];
}
console.log('FILTERED: score=' + score + ' < 5');
return [];

const genNode = $("HTTP Request — генерация поста").first().json;
const srcNode = $("Code — фильтр оценки").first().json || {};

const fullText = genNode.choices?.[0]?.message?.content || '';

if (!fullText || fullText.trim().toUpperCase().startsWith('NOPOST')) {
  console.log('БЛОКИРОВКА: NOPOST или пустой ответ Claude');
  return [];
}

const imageIndex = fullText.lastIndexOf('IMAGE:');
let image_prompt = 'Modern Moscow business center interior, professional real estate photography, luxury office space, natural lighting, no people, 4k';
let bodyText = fullText.trim();
if (imageIndex !== -1) {
  image_prompt = fullText.substring(imageIndex + 6).replace(/\*\*/g, '').trim();
  bodyText = fullText.substring(0, imageIndex).trim();
}

const postStart = bodyText.indexOf('📍');
if (postStart === -1) {
  console.log('БЛОКИРОВКА: нет 📍 в ответе Claude, формат нарушен, пост отброшен');
  return [];
}

let tg_post = bodyText.substring(postStart);
tg_post = tg_post.replace(/\*\*/g, '').replace(/^#.*\n+/, '').trim();
tg_post = tg_post + '\n\n#Грандвест #коммерческаянедвижимость #новостройки #аренда #ипотека';

if (tg_post.length < 300) {
  console.log('БЛОКИРОВКА: пост слишком короткий (' + tg_post.length + ' симв)');
  return [];
}

const SHORT_LIMIT = 1024 - 68 - 20;
let image_url = '';

if (tg_post.length <= SHORT_LIMIT) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://fal.run/fal-ai/flux/schnell',
      headers: {
        'Authorization': 'Key [REDACTED_FAL_KEY]',
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        prompt: image_prompt,
        image_size: 'landscape_16_9',
        num_inference_steps: 4,
        num_images: 1,
        enable_safety_checker: true
      }),
      timeout: 20000,
      family: 4
    });
    image_url = response.images?.[0]?.url || '';
  } catch (e) {
    console.log('fal.ai error: ' + e.message);
  }
}

return [{
  json: {
    tg_post,
    image_prompt,
    image_url,
    title: srcNode.title || '',
    source_name: srcNode.channel ? '@' + srcNode.channel : '',
    source_url: srcNode.source_url || '',
    score: srcNode.score || 0
  }
}];

const generated = $input.first().json;
const text = generated.choices?.[0]?.message?.content || '';

const src = $('Code — фильтр оценки').first().json;

if (!text || text.length < 20) {
  console.log('Extract: empty or too short text');
  return [];
}

return [{
  json: {
    text: text,
    channel: src.channel || '',
    source_url: src.source_url || '',
    time_msk: src.pub_time || src.time_msk || '',
    score: src.score || 0,
    score_reason: src.score_reason || ''
  }
}];

