const postText = postData.tg_post;
const imageUrl = postData.image_url || '';

if (!postText || postText.length < 10) {
  throw new Error('tg_post пустой');
}

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.github.com/repos/Smariovin/grandvest/actions/workflows/grandvest-publisher.yml/dispatches',
  headers: {
    'Authorization': 'token [REDACTED_GITHUB_TOKEN]',
    'Accept': 'application/vnd.github+json',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    ref: 'main',
    inputs: {
      message: postText,
      image_url: imageUrl,
      source_url: postData.source_url || '',
      source_name: postData.source_name || '',
      parser_name: 'Парсер Telegram'
    }
  })
});
return [{ json: { ok: true } }];

